import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface AppBreakdown {
  app: string;
  minutes: number;
}

interface Data {
  dailyUsage: {
    totalMinutes: number;
    pickups: number;
  };
  appBreakdown: AppBreakdown[];
  weeklyTrend: number[];
}

interface Meta {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const data = response.data as Data;
  const meta = response.meta as Meta;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 0.5 }}>
              Daily Screen Time
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: meta.primaryColor }}>
              {Math.floor(data.dailyUsage.totalMinutes / 60)}h {data.dailyUsage.totalMinutes % 60}m
            </Typography>
            <Typography variant="body2" sx={{ color: '#F8FAFC', mt: 0.5 }}>
              {data.dailyUsage.pickups} pickups
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {data.appBreakdown.slice(0, 3).map((appData) => (
              <Chip
                key={appData.app}
                label={`${appData.app}: ${appData.minutes}m`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: meta.accentColor, color: '#FFFFFF' }}
              />
            ))}
          </Stack>

          <Box sx={{ width: '100%', height: 120 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: data.weeklyTrend,
                  color: meta.primaryColor,
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[{ data: data.weeklyTrend.map((_, i) => i), hide: true }]}
              yAxis={[{ id: 'minutes' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="minutes"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="minutes"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
